	"istio.io/istio/pkg/kube/inject"
	"istio.io/istio/pkg/ptr"
	"istio.io/istio/pkg/revisions"
)

// TestGatewayStatusUpdateDoesNotTriggerReconciliation tests that status-only updates
// do not trigger the deployment controller reconciliation loop
func TestGatewayStatusUpdateDoesNotTriggerReconciliation(t *testing.T) {
	client := kube.NewFakeClient()

	// Create a namespace
	ns := &corev1.Namespace{
		ObjectMeta: metav1.ObjectMeta{
			Name: "default",
		},
	}
	if _, err := client.Kube().CoreV1().Namespaces().Create(nil, ns, metav1.CreateOptions{}); err != nil {
		t.Fatal(err)
	}

	// Create a GatewayClass
	gc := &k8sbeta.GatewayClass{
		ObjectMeta: metav1.ObjectMeta{
			Name: "istio",
		},
		Spec: k8s.GatewayClassSpec{
			ControllerName: k8s.GatewayController(features.ManagedGatewayController),
		},
	}
	if _, err := client.GatewayAPI().GatewayV1beta1().GatewayClasses().Create(nil, gc, metav1.CreateOptions{}); err != nil {
		t.Fatal(err)
	}

	// Create a Gateway
	gw := &k8sbeta.Gateway{
		ObjectMeta: metav1.ObjectMeta{
			Name:       "test-gateway",
			Namespace:  "default",
			Generation: 1,
		},
		Spec: k8s.GatewaySpec{
			GatewayClassName: "istio",
			Listeners: []k8s.Listener{
				{
					Name:     "http",
					Port:     80,
					Protocol: k8s.HTTPProtocolType,
				},
			},
		},
	}

	if _, err := client.GatewayAPI().GatewayV1beta1().Gateways("default").Create(nil, gw, metav1.CreateOptions{}); err != nil {
		t.Fatal(err)
	}

	// Setup the deployment controller with a tracking queue
	reconcileCount := 0
	trackingQueue := make(chan string, 100)

	tw := revisions.NewTagWatcher(client, "")
	meshConfig := mesh.DefaultMeshConfig()
	env := &model.Environment{Watcher: mesh.NewFixedWatcher(meshConfig)}

	dc := NewDeploymentController(
		client,
		cluster.ID("test-cluster"),
		env,
		func() inject.WebhookConfig {
			return inject.WebhookConfig{
				Templates: map[string]string{
					"kube-gateway": "test-template",
				},
				Values:     nil,
				MeshConfig: meshConfig,
			}
		},
		func(fn func()) {
			// No-op for injection handler
		},
		tw,
		"",
		constants.IstioSystemNamespace,
	)

	// Override the Reconcile function to track calls
	originalReconcile := dc.Reconcile
	dc.queue = &trackingQueueWrapper{
		Queue: dc.queue,
		onReconcile: func(key string) {
			reconcileCount++
			trackingQueue <- key
			originalReconcile(key)
		},
	}

	// Start the controller
	stop := make(chan struct{})
	defer close(stop)
	go dc.Run(stop)

	// Wait for initial sync
	time.Sleep(100 * time.Millisecond)

	// Clear any initial reconciliations
	initialCount := reconcileCount
	for len(trackingQueue) > 0 {
		<-trackingQueue
	}

	t.Logf("Initial reconcile count: %d", initialCount)

	// Now update only the status (not the spec)
	gw.Status = k8s.GatewayStatus{
		Conditions: []metav1.Condition{
			{
				Type:               "Ready",
				Status:             "True",
				LastTransitionTime: metav1.Now(),
				Reason:             "Ready",
				Message:            "Gateway is ready",
			},
		},
		Addresses: []k8s.GatewayStatusAddress{
			{
				Type:  ptr.Of(k8s.IPAddressType),
				Value: "10.0.0.1",
			},
		},
	}

	// Update status - this should NOT trigger reconciliation
	if _, err := client.GatewayAPI().GatewayV1beta1().Gateways("default").UpdateStatus(nil, gw, metav1.UpdateOptions{}); err != nil {
		t.Fatal(err)
	}

	// Wait a bit to see if reconciliation is triggered
	time.Sleep(200 * time.Millisecond)

	statusUpdateReconcileCount := reconcileCount - initialCount

	if statusUpdateReconcileCount > 0 {
		t.Errorf("Status-only update triggered %d reconciliation(s), expected 0", statusUpdateReconcileCount)
	} else {
		t.Logf("✓ Status-only update did not trigger reconciliation (as expected)")
	}

	// Now update the spec - this SHOULD trigger reconciliation
	gw.Spec.Listeners = append(gw.Spec.Listeners, k8s.Listener{
		Name:     "https",
		Port:     443,
		Protocol: k8s.HTTPSProtocolType,
	})
	gw.Generation = 2 // Simulate generation increment

	if _, err := client.GatewayAPI().GatewayV1beta1().Gateways("default").Update(nil, gw, metav1.UpdateOptions{}); err != nil {
		t.Fatal(err)
	}

	// Wait for reconciliation
	time.Sleep(200 * time.Millisecond)

	specUpdateReconcileCount := reconcileCount - initialCount - statusUpdateReconcileCount

	if specUpdateReconcileCount == 0 {
		t.Errorf("Spec update did not trigger reconciliation, expected at least 1")
	} else {
		t.Logf("✓ Spec update triggered %d reconciliation(s) (as expected)", specUpdateReconcileCount)
	}
}

// trackingQueueWrapper wraps a Queue to track reconciliation calls
type trackingQueueWrapper struct {
	controllers.Queue
	onReconcile func(key string)
}

func (q *trackingQueueWrapper) Add(item any) {
	if key, ok := item.(string); ok && q.onReconcile != nil {
		q.onReconcile(key)
	}
	q.Queue.Add(item)
}

