	dc.SetQueue(controllers.NewQueue("gateway deployment test",
		controllers.WithReconciler(func(key types.NamespacedName) error {
			reconcileCount.Add(1)
			fmt.Printf("Reconcile called for %s, count: %d\n", key, reconcileCount.Load())
