		t.Errorf("BUG REPRODUCED: Status-only update (attachedRoutes) triggered %d reconciliation(s), expected 0", statusUpdateCount)
	} else {
		t.Logf("✓ Status-only update did not trigger reconciliation (FIXED)")
	}

