	specUpdateCount := reconcileCount.Load()
	fmt.Printf("Reconciliations after spec update: %d\n", specUpdateCount)

	if specUpdateCount == 0 {
		t.Errorf("Spec update did not trigger reconciliation, expected at least 1")
	} else {
