	testing.Main(func(pat, str string) (bool, error) { return true, nil },
		[]testing.InternalTest{
			{
				Name: "TestGatewayStatusUpdateDoesNotTriggerReconciliation",
				F:    TestGatewayStatusUpdateDoesNotTriggerReconciliation,
			},
		},
		nil,
		nil,
	)
}

