	}

	// Track reconciliations via the patcher
	dc.patcher = func(gvr schema.GroupVersionResource, name string, namespace string, data []byte, subresources ...string) error {
		reconciles.Inc()
		t.Logf("Reconcile: patcher called for %v %s/%s, total count: %d", gvr, namespace, name, reconciles.Load())
		return nil
	}

	stop := test.NewStop(t)
	gws := clienttest.Wrap(t, dc.gateways)
	go tw.Run(stop)
	go dc.Run(stop)
	client.RunAndWait(stop)
	kube.WaitForCacheSync("test", stop, dc.queue.HasSynced)

