// TestGatewayStatusUpdateDoesNotTriggerReconciliation tests that status-only updates
// do not trigger the deployment controller reconciliation loop.
// This is a regression test for: "Gateway deployer runs deployment loop on each Gateway status update"
func TestGatewayStatusUpdateDoesNotTriggerReconciliation(t *testing.T) {
	client := kube.NewFakeClient()

	// Create a namespace
	ns := &corev1.Namespace{
		ObjectMeta: metav1.ObjectMeta{
			Name: "default",
		},
	}
	if _, err := client.Kube().CoreV1().Namespaces().Create(nil, ns, metav1.CreateOptions{}); err != nil {
		t.Fatal(err)
	}

	// Create a GatewayClass
	gc := &k8sbeta.GatewayClass{
		ObjectMeta: metav1.ObjectMeta{
			Name: "istio",
		},
		Spec: k8s.GatewayClassSpec{
			ControllerName: k8s.GatewayController(features.ManagedGatewayController),
		},
	}
	if _, err := client.GatewayAPI().GatewayV1beta1().GatewayClasses().Create(nil, gc, metav1.CreateOptions{}); err != nil {
		t.Fatal(err)
	}

	// Create a Gateway with Generation=1
	gw := &k8sbeta.Gateway{
		ObjectMeta: metav1.ObjectMeta{
			Name:            "test-gateway",
			Namespace:       "default",
			Generation:      1,
			ResourceVersion: "1",
		},
		Spec: k8s.GatewaySpec{
			GatewayClassName: "istio",
			Listeners: []k8s.Listener{
				{
					Name:     "http",
					Port:     80,
					Protocol: k8s.HTTPProtocolType,
				},
			},
		},
	}

	if _, err := client.GatewayAPI().GatewayV1beta1().Gateways("default").Create(nil, gw, metav1.CreateOptions{}); err != nil {
		t.Fatal(err)
	}

	// Setup the deployment controller with a tracking reconciler
	var reconcileCount atomic.Int32

	tw := revisions.NewTagWatcher(client, "")
	meshConfig := mesh.DefaultMeshConfig()
	env := &model.Environment{Watcher: mesh.NewFixedWatcher(meshConfig)}

	dc := NewDeploymentController(
		client,
		cluster.ID("test-cluster"),
		env,
		func() inject.WebhookConfig {
			return inject.WebhookConfig{
				Templates: map[string]string{
					"kube-gateway": "test-template",
				},
				Values:     nil,
				MeshConfig: meshConfig,
			}
		},
		func(fn func()) {
			// No-op for injection handler
		},
		tw,
		"",
		constants.IstioSystemNamespace,
	)

	// Override the queue with one that tracks reconciliations
	dc.queue = controllers.NewQueue("gateway deployment test",
		controllers.WithReconciler(func(key types.NamespacedName) error {
			count := reconcileCount.Add(1)
			t.Logf("Reconcile called for %s, total count: %d", key, count)
			return dc.Reconcile(key)
		}),
		controllers.WithMaxAttempts(5))

	// Start the controller
	stop := make(chan struct{})
	defer close(stop)
	client.RunAndWait(stop)
	tw.Run(stop)
	go dc.Run(stop)

	// Wait for initial sync and reconciliation
	time.Sleep(500 * time.Millisecond)

	// Clear initial count
	initialCount := reconcileCount.Load()
	t.Logf("Initial reconcile count: %d", initialCount)
	reconcileCount.Store(0)

	// Test 1: Update only the status (Generation stays 1)
	// This simulates the frequent attachedRoutes updates mentioned in the bug report
	gw, err := client.GatewayAPI().GatewayV1beta1().Gateways("default").Get(nil, "test-gateway", metav1.GetOptions{})
	if err != nil {
		t.Fatal(err)
	}

	// Simulate status update - Generation stays the same, but ResourceVersion changes
	gw.ResourceVersion = "2"
	gw.Status = k8s.GatewayStatus{
		Conditions: []metav1.Condition{
			{
				Type:               "Ready",
				Status:             "True",
				LastTransitionTime: metav1.Now(),
				Reason:             "Ready",
				Message:            "Gateway is ready",
			},
		},
		Listeners: []k8s.ListenerStatus{
			{
				Name:           "http",
				AttachedRoutes: 5, // This is the field that changes frequently!
			},
		},
	}

	t.Log("Updating Gateway status (attachedRoutes changed)...")
	if _, err := client.GatewayAPI().GatewayV1beta1().Gateways("default").UpdateStatus(nil, gw, metav1.UpdateOptions{}); err != nil {
		t.Fatal(err)
	}

	// Wait to see if reconciliation is triggered
	time.Sleep(300 * time.Millisecond)

	statusUpdateCount := reconcileCount.Load()
	t.Logf("Reconciliations after status update: %d", statusUpdateCount)

	if statusUpdateCount > 0 {
		t.Errorf("BUG: Status-only update (attachedRoutes) triggered %d reconciliation(s), expected 0. "+
			"The deployment controller should not run on status updates.", statusUpdateCount)
	} else {
		t.Log("✓ Status-only update did not trigger reconciliation (bug is fixed)")
	}

	// Test 2: Update the spec (Generation increments to 2)
	// This should trigger reconciliation
	reconcileCount.Store(0)

	gw, err = client.GatewayAPI().GatewayV1beta1().Gateways("default").Get(nil, "test-gateway", metav1.GetOptions{})
	if err != nil {
		t.Fatal(err)
	}

	gw.Generation = 2
	gw.ResourceVersion = "3"
	gw.Spec.Listeners = append(gw.Spec.Listeners, k8s.Listener{
		Name:     "https",
		Port:     443,
		Protocol: k8s.HTTPSProtocolType,
	})

	t.Log("Updating Gateway spec (adding HTTPS listener)...")
	if _, err := client.GatewayAPI().GatewayV1beta1().Gateways("default").Update(nil, gw, metav1.UpdateOptions{}); err != nil {
		t.Fatal(err)
	}

	// Wait for reconciliation
	time.Sleep(300 * time.Millisecond)

	specUpdateCount := reconcileCount.Load()
	t.Logf("Reconciliations after spec update: %d", specUpdateCount)

	if specUpdateCount == 0 {
		t.Error("Spec update did not trigger reconciliation, expected at least 1")
	} else {
		t.Logf("✓ Spec update triggered %d reconciliation(s) (as expected)", specUpdateCount)
	}

	// Test 3: Multiple status updates should not accumulate reconciliations
	reconcileCount.Store(0)

	for i := 0; i < 5; i++ {
		gw, err = client.GatewayAPI().GatewayV1beta1().Gateways("default").Get(nil, "test-gateway", metav1.GetOptions{})
		if err != nil {
			t.Fatal(err)
		}

		// Simulate frequent attachedRoutes updates (the main issue in the bug report)
		gw.ResourceVersion = fmt.Sprintf("%d", 10+i)
		gw.Status.Listeners[0].AttachedRoutes = int32(10 + i)

		if _, err := client.GatewayAPI().GatewayV1beta1().Gateways("default").UpdateStatus(nil, gw, metav1.UpdateOptions{}); err != nil {
			t.Fatal(err)
		}
	}

	// Wait to see if any reconciliations were triggered
	time.Sleep(300 * time.Millisecond)

	multipleStatusUpdateCount := reconcileCount.Load()
	t.Logf("Reconciliations after 5 status updates: %d", multipleStatusUpdateCount)

	if multipleStatusUpdateCount > 0 {
		t.Errorf("BUG: 5 status-only updates triggered %d reconciliation(s), expected 0. "+
			"This shows the expensive deployment loop is still running on frequent status updates.", multipleStatusUpdateCount)
	} else {
		t.Log("✓ Multiple status-only updates did not trigger reconciliation (bug is fixed)")
	}
}

