// TestGatewayStatusUpdateDoesNotTriggerReconciliation tests that status-only updates
// do not trigger the deployment controller reconciliation loop.
// This is a regression test for: "Gateway deployer runs deployment loop on each Gateway status update"
func TestGatewayStatusUpdateDoesNotTriggerReconciliation(t *testing.T) {
	client := kube.NewFakeClient(&corev1.Namespace{
		ObjectMeta: metav1.ObjectMeta{
			Name: "default",
		},
	})

	tw := revisions.NewTagWatcher(client, "")
	env := &model.Environment{}
	dc := NewDeploymentController(client, cluster.ID("test-cluster"), env, testInjectionConfig(t, ""), func(fn func()) {}, tw, "", "")

	reconciles := atomic.NewInt32(0)
	wantReconcile := int32(0)
	expectReconciled := func() {
		t.Helper()
		wantReconcile++
		assert.EventuallyEqual(t, reconciles.Load, wantReconcile, retry.Timeout(time.Second*5), retry.Message("no reconciliation"))
	}
	expectNoReconcile := func() {
		t.Helper()
		// Wait a bit to make sure no reconciliation happens
		time.Sleep(300 * time.Millisecond)
		assert.Equal(t, reconciles.Load(), wantReconcile, "unexpected reconciliation")
	}

	// Track reconciliations via the patcher
	dc.patcher = func(gvr schema.GroupVersionResource, name string, namespace string, data []byte, subresources ...string) error {
		reconciles.Inc()
		t.Logf("Reconcile: patcher called for %v %s/%s, total count: %d", gvr, namespace, name, reconciles.Load())
		return nil
	}

	stop := test.NewStop(t)
	gws := clienttest.Wrap(t, dc.gateways)
	go tw.Run(stop)
	go dc.Run(stop)
	client.RunAndWait(stop)
	kube.WaitForCacheSync("test", stop, dc.queue.HasSynced)

	// Test 1: Update only the status (Generation stays 1)
	// This simulates the frequent attachedRoutes updates mentioned in the bug report
	gw, err := client.GatewayAPI().GatewayV1beta1().Gateways("default").Get(nil, "test-gateway", metav1.GetOptions{})
	if err != nil {
		t.Fatal(err)
	}

