	defaultGateway.Status = k8s.GatewayStatus{
		Conditions: []metav1.Condition{
			{
				Type:               "Ready",
				Status:             "True",
				LastTransitionTime: metav1.Now(),
				Reason:             "Ready",
				Message:            "Gateway is ready",
			},
		},
		Listeners: []k8s.ListenerStatus{
			{
				Name:           "http",
				AttachedRoutes: 5, // This is the field that changes frequently!
			},
		},
	}
	gws.UpdateStatus(defaultGateway)
	expectNoReconcile()
	t.Log("✓ Status-only update did not trigger reconciliation (bug is fixed)")

	// Test 2: Multiple status updates should not accumulate reconciliations
	t.Log("Test 2: Multiple status updates...")
	for i := 0; i < 5; i++ {
		defaultGateway.Status.Listeners[0].AttachedRoutes = int32(10 + i)
		gws.UpdateStatus(defaultGateway)
	}
	expectNoReconcile()
	t.Log("✓ Multiple status-only updates did not trigger reconciliation (bug is fixed)")

	// Test 3: Update the spec (Generation increments to 2)
	// This SHOULD trigger reconciliation
	t.Log("Test 3: Spec update (adding HTTPS listener)...")
	defaultGateway.Generation = 2
	defaultGateway.Spec.Listeners = append(defaultGateway.Spec.Listeners, k8s.Listener{
		Name:     "https",
		Port:     443,
		Protocol: k8s.HTTPSProtocolType,
	})
	gws.Update(defaultGateway)
	expectReconciled()
	t.Log("✓ Spec update triggered reconciliation (as expected)")

	// Test 4: Another status update after spec change should still not trigger reconciliation
	t.Log("Test 4: Status update after spec change...")
	defaultGateway.Status.Listeners[0].AttachedRoutes = 100
	gws.UpdateStatus(defaultGateway)
	expectNoReconcile()
	t.Log("✓ Status-only update after spec change did not trigger reconciliation (bug is fixed)")
}

